use kuchiki::traits::*;

fn main() {
    let html = r#"<html><body><p>x</p></body></html>"#;

    let doc = kuchiki::parse_html().one(html);

    // Approach 1: select, then for each match remove descendants
    println!("=== Approach 1: select body, remove p, serialize ===");
    let doc1 = kuchiki::parse_html().one(html);
    for m in doc1.select("body").unwrap() {
        for r in m.as_node().select("p").unwrap() {
            r.as_node().detach();
        }
        let mut buf = vec![];
        m.as_node().serialize(&mut buf).unwrap();
        println!("{}", String::from_utf8_lossy(&buf));
    }

    println!("=== Approach 2: remove all p first, then select body ===");
    let doc2 = kuchiki::parse_html().one(html);
    for r in doc2.select("p").unwrap() {
        r.as_node().detach();
    }
    for m in doc2.select("body").unwrap() {
        let mut buf = vec![];
        m.as_node().serialize(&mut buf).unwrap();
        println!("{}", String::from_utf8_lossy(&buf));
    }

    println!("=== Approach 3: simultaneous, lazy iter ===");
    let doc3 = kuchiki::parse_html().one(html);
    for m in doc3.select("body").unwrap() {
        for r in doc3.select("p").unwrap() {
            r.as_node().detach();
        }
        let mut buf = vec![];
        m.as_node().serialize(&mut buf).unwrap();
        println!("{}", String::from_utf8_lossy(&buf));
    }
}
