    println!("=== Approach 14: maybe select walks descendants, detach breaks walk ===");
    let doc = kuchiki::parse_html().one(html);
    {
        // outer iter is for the SELECT
        // Try select(html) and detach p inside via select within
        let outer = doc.select("body").unwrap();
        for body_match in outer {
            // call select("p") on document, get iter, detach
            let inner_iter = doc.select("p").unwrap();
            for p_match in inner_iter {
                p_match.as_node().detach();
            }
            let mut buf = vec![];
            body_match.as_node().serialize(&mut buf).unwrap();
            println!("body output: {}", String::from_utf8_lossy(&buf));
        }
    }
}
