use kuchiki::traits::*;
use kuchiki::NodeRef;

fn print_tree(node: &NodeRef, depth: usize) {
    let indent = "  ".repeat(depth);
    if let Some(elem) = node.as_element() {
        println!("{}<{}>", indent, elem.name.local);
    } else if let Some(text) = node.as_text() {
        let t = text.borrow();
        let t = t.trim();
        if !t.is_empty() {
            println!("{}\"{}\"", indent, t);
        }
    } else if node.as_document().is_some() {
        println!("{}<<document>>", indent);
    } else if node.as_doctype().is_some() {
        println!("{}<<doctype>>", indent);
    }
    for c in node.children() {
        print_tree(&c, depth + 1);
    }
}

fn main() {
    let inputs = vec![
        r#"<html><body><p>x</p></body></html>"#,
        r#"<html><body><p>x</p><div>y</div></body></html>"#,
        r#"<p>x</p>"#,
    ];

    for input in inputs {
        println!("=== INPUT: {} ===", input);
        let doc = kuchiki::parse_html().one(input);
        print_tree(&doc, 0);
        println!();
    }

    println!("=== Test: detach p, see what remains ===");
    let doc = kuchiki::parse_html().one(r#"<html><body><p>x</p></body></html>"#);
    for r in doc.select("p").unwrap() {
        r.as_node().detach();
    }
    print_tree(&doc, 0);

    println!("=== Test: detach body, see what remains ===");
    let doc = kuchiki::parse_html().one(r#"<html><body><p>x</p></body></html>"#);
    for r in doc.select("body").unwrap() {
        r.as_node().detach();
    }
    print_tree(&doc, 0);
}
