                .short("B")
                .long("detect-base")
                .help("Try to detect the base URL from the <base> tag in the document. If not found, default to the value of --base, if supplied"),
        )
        .arg(
            Arg::with_name("ignore-whitespace")
                .short("w")
                .long("ignore-whitespace")
                .help("When printing text nodes, ignore those that consist entirely of whitespace"),
        )
        .arg(
            Arg::with_name("pretty")
                .short("p")
                .long("pretty")
                .help("Pretty-print the serialised output"),
        )
        .arg(
            Arg::with_name("text")
                .short("t")
                .long("text")
                .help("Output only the contents of text nodes inside selected elements"),
        )
        .arg(
            Arg::with_name("attribute")
                .short("a")
                .long("attribute")
                .takes_value(true)
                .value_name("attribute")
                .help("Only return this attribute (if present) from selected elements"),
        )
        .arg(
            Arg::with_name("base")
                .short("b")
                .long("base")
                .takes_value(true)
                .value_name("base")
                .help("Use this URL as the base for links"),
        )
        .arg(
            Arg::with_name("filename")
                .short("f")
                .long("filename")
                .takes_value(true)
                .value_name("FILE")
                .help("The input file. Defaults to stdin"),
        )
        .arg(
            Arg::with_name("output")
                .short("o")
                .long("output")
                .takes_value(true)
                .value_name("FILE")
                .help("The output file. Defaults to stdout"),
        )
        .arg(
            Arg::with_name("remove-nodes")
                .short("r")
                .long("remove-nodes")
                .takes_value(true)
                .value_name("SELECTOR")
                .multiple(true)
                .help("Remove nodes matching this expression before output. May be specified multiple times"),
        )
        .arg(
            Arg::with_name("selector")
                .multiple(true)
                .default_value("html")
                .help("The CSS expression to select"),
        );

    let matches = app.get_matches();

    let pretty = matches.is_present("pretty");
    let text_mode = matches.is_present("text");
    let ignore_ws = matches.is_present("ignore-whitespace");
    let detect_base = matches.is_present("detect-base");
    let attribute = matches.value_of("attribute");
    let cli_base = matches.value_of("base");
    let filename = matches.value_of("filename");
    let output_file = matches.value_of("output");

    let selectors: Vec<&str> = matches.values_of("selector").unwrap().collect();
    let selector_str: String = selectors.join(" ");

    let remove_nodes: Vec<&str> = matches
        .values_of("remove-nodes")
        .map(|v| v.collect())
        .unwrap_or_default();

    // Read input
    let mut input = String::new();
    if let Some(path) = filename {
        let mut file = File::open(path).expect("should have opened input file");
        file.read_to_string(&mut input).expect("should have read input file");
    } else {
        std::io::stdin().read_to_string(&mut input).expect("should have read stdin");
    }

    // Parse HTML
    let document = kuchiki::parse_html().one(input);

    // Determine effective base URL
    let mut base_url: Option<Url> = None;
    if detect_base {
        if let Ok(matched) = document.select("base") {
            for m in matched {
                let attrs = m.attributes.borrow();
                if let Some(href) = attrs.get("href") {
                    if let Ok(url) = Url::parse(href) {
                        base_url = Some(url);
                        break;
                    }
                }
            }
        }
    }
    if base_url.is_none() {
        if let Some(b) = cli_base {
            if let Ok(url) = Url::parse(b) {
                base_url = Some(url);
            }
        }
    }

    // Detach nodes matching --remove-nodes BEFORE selection
    for r in &remove_nodes {
        if let Ok(matched) = document.select(r) {
            let to_detach: Vec<NodeRef> = matched.map(|d| d.as_node().clone()).collect();
            for n in to_detach {
                n.detach();
            }
        }
    }

    // Open output sink
    let mut output: Box<dyn Write> = match output_file {
        Some(path) => Box::new(File::create(path).expect("should have created output file")),
        None => Box::new(std::io::stdout()),
    };

    // Compile main selector. Panic with the same format as the reference on failure.
    let select_iter = match document.select(&selector_str) {
        Ok(it) => it,
        Err(_) => {
            panic!("Failed to parse CSS selector: ({})", selector_str);
        }
    };

    for m in select_iter {
        // Apply base URL rewriting on <a> if matched node is an <a>
        if let Some(ref base) = base_url {
            apply_base_to_anchor(&m, base);
        }

        if let Some(attr) = attribute {
            let attrs = m.attributes.borrow();
            if let Some(value) = attrs.get(attr) {
                writeln!(output, "{}", value).ok();
            }
        } else if text_mode {
            if ignore_ws {
                for desc in m.as_node().inclusive_descendants() {
                    if let Some(t) = desc.as_text() {
                        let t = t.borrow();
                        if !t.trim().is_empty() {
                            writeln!(output, "{}", t).ok();
                        }
                    }
                }
                writeln!(output).ok();
            } else {
                let mut buf = String::new();
                for desc in m.as_node().inclusive_descendants() {
                    if let Some(t) = desc.as_text() {
                        buf.push_str(&t.borrow());
                    }
                }
                writeln!(output, "{}", buf).ok();
            }
        } else if pretty {
            pretty_print(&mut output, m.as_node(), 0);
        } else {
            m.as_node().serialize(&mut output).ok();
            writeln!(output).ok();
        }
    }
}

fn apply_base_to_anchor(node: &NodeDataRef<ElementData>, base: &Url) {
    if node.name.local.as_ref() != "a" {
        return;
    }
    let mut attrs = node.attributes.borrow_mut();
    if let Some(href) = attrs.get("href").map(|s| s.to_string()) {
        if let Ok(joined) = base.join(&href) {
            attrs.insert("href", joined.to_string());
        }
    }
}

fn is_inline(name: &str) -> bool {
    matches!(
        name,
        "a" | "abbr" | "acronym" | "b" | "bdo" | "big" | "br" | "button"
            | "cite" | "code" | "dfn" | "em" | "i" | "img" | "input"
            | "kbd" | "label" | "map" | "object" | "output" | "q"
            | "samp" | "script" | "select" | "small" | "span" | "strong"
            | "sub" | "sup" | "textarea" | "time" | "tt" | "u" | "var"
            | "wbr"
    )
}

fn is_void(name: &str) -> bool {
    matches!(
        name,
        "area" | "base" | "br" | "col" | "embed" | "hr" | "img" | "input"
            | "link" | "meta" | "param" | "source" | "track" | "wbr"
    )
}

fn pretty_print(out: &mut dyn Write, node: &NodeRef, depth: usize) {
    write_pretty(out, node, depth, &mut PrettyState::default());
}

#[derive(Default)]
struct PrettyState {
    pending_newline: bool,
}

fn write_pretty(out: &mut dyn Write, node: &NodeRef, depth: usize, st: &mut PrettyState) {
    if let Some(elem) = node.as_element() {
        let name = elem.name.local.as_ref().to_string();
        let attrs = elem.attributes.borrow();
        let mut attr_str = String::new();
        for (k, v) in attrs.map.iter() {
            attr_str.push(' ');
            attr_str.push_str(&k.local);
            attr_str.push_str("=\"");
            attr_str.push_str(&v.value);
            attr_str.push('"');
        }
        let indent = " ".repeat(depth * 2);

        if is_void(&name) {
            if st.pending_newline {
                writeln!(out).ok();
                write!(out, "{}", indent).ok();
            }
            write!(out, "<{}{}>", name, attr_str).ok();
            writeln!(out).ok();
            st.pending_newline = false;
        } else {
            writeln!(out).ok();
            write!(out, "{}<{}{}>", indent, name, attr_str).ok();

            // Walk children
            let children: Vec<NodeRef> = node.children().collect();
            let mut wrote_any = false;
            let mut last_was_inline_text = false;
            for child in &children {
                if let Some(t) = child.as_text() {
                    let tref = t.borrow();
                    let s: &str = &tref;
                    if s.trim().is_empty() && !wrote_any {
                        // Skip leading whitespace
                        continue;
                    }
                    // Text: inline if first content, else with newline+indent
                    if !wrote_any {
                        write!(out, "{}", s).ok();
                        last_was_inline_text = true;
                    } else {
                        writeln!(out).ok();
                        let child_indent = " ".repeat((depth + 1) * 2);
                        write!(out, "{}{}", child_indent, s).ok();
                        last_was_inline_text = false;
                    }
                    wrote_any = true;
                } else if let Some(child_elem) = child.as_element() {
                    let child_name = child_elem.name.local.as_ref();
                    if is_inline(child_name) {
                        // Inline element: emit without newline
                        let child_attrs = child_elem.attributes.borrow();
                        let mut child_attr_str = String::new();
                        for (k, v) in child_attrs.map.iter() {
                            child_attr_str.push(' ');
                            child_attr_str.push_str(&k.local);
                            child_attr_str.push_str("=\"");
                            child_attr_str.push_str(&v.value);
                            child_attr_str.push('"');
                        }
                        if is_void(child_name) {
                            write!(out, "<{}{}>", child_name, child_attr_str).ok();
                        } else {
                            write!(out, "<{}{}>", child_name, child_attr_str).ok();
                            // Recurse on children, but in inline form (no newline)
                            inline_serialize(out, child);
                            write!(out, "</{}>", child_name).ok();
                        }
                        last_was_inline_text = false;
                    } else {
                        // Block element child
                        write_pretty(out, child, depth + 1, st);
                        last_was_inline_text = false;
                    }
                    wrote_any = true;
                }
            }
            writeln!(out).ok();
            write!(out, "{}</{}>", indent, name).ok();
            if depth == 0 {
                writeln!(out).ok();
            }
            st.pending_newline = false;
        }
    }
}

fn inline_serialize(out: &mut dyn Write, node: &NodeRef) {
    for child in node.children() {
        if let Some(t) = child.as_text() {
            write!(out, "{}", t.borrow()).ok();
        } else if let Some(elem) = child.as_element() {
            let name = elem.name.local.as_ref();
            let attrs = elem.attributes.borrow();
            let mut attr_str = String::new();
            for (k, v) in attrs.map.iter() {
                attr_str.push(' ');
                attr_str.push_str(&k.local);
                attr_str.push_str("=\"");
                attr_str.push_str(&v.value);
                attr_str.push('"');
            }
            if is_void(name) {
                write!(out, "<{}{}>", name, attr_str).ok();
            } else {
                write!(out, "<{}{}>", name, attr_str).ok();
                inline_serialize(out, &child);
                write!(out, "</{}>", name).ok();
            }
        }
    }
}

