fn escape_text(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for c in s.chars() {
        match c {
            '&' => out.push_str("&amp;"),
            '\u{00A0}' => out.push_str("&nbsp;"),
            '<' => out.push_str("&lt;"),
            '>' => out.push_str("&gt;"),
            c => out.push(c),
        }
    }
    out
}

fn escape_attr(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for c in s.chars() {
        match c {
            '&' => out.push_str("&amp;"),
            '\u{00A0}' => out.push_str("&nbsp;"),
            '"' => out.push_str("&quot;"),
            c => out.push(c),
        }
    }
    out
}

fn open_tag(elem: &ElementData) -> String {
    let name = elem.name.local.as_ref();
    let attrs = elem.attributes.borrow();
    let mut s = String::new();
    s.push('<');
    s.push_str(name);
    for (key, attr) in attrs.map.iter() {
        s.push(' ');
        s.push_str(key.local.as_ref());
        s.push_str("=\"");
        s.push_str(&escape_attr(&attr.value));
        s.push('"');
    }
    s.push('>');
    s
}

#[derive(PartialEq, Clone, Copy)]
enum Prev {
    None,
    Text,
    Inline,
    Block,
}

// Serialize an element and all descendants with no added whitespace.
fn write_inline(out: &mut String, node: &NodeRef) {
    if let Some(elem) = node.as_element() {
        let name = elem.name.local.as_ref();
        out.push_str(&open_tag(elem));
        if is_void(name) {
            return;
        }
        for child in node.children() {
            if child.as_element().is_some() {
                write_inline(out, &child);
            } else if let Some(t) = child.as_text() {
                out.push_str(&escape_text(&t.borrow()));
            }
        }
        out.push_str("</");
        out.push_str(name);
        out.push('>');
    } else if let Some(t) = node.as_text() {
        out.push_str(&escape_text(&t.borrow()));
    }
}

// Render the children of `node`. Children sit at indent level `depth`.
fn pretty_children(out: &mut String, node: &NodeRef, depth: usize, expanded: bool) {
    let indent = "  ".repeat(depth);
    let mut prev = Prev::None;
    for child in node.children() {
        if let Some(t) = child.as_text() {
            let value = t.borrow();
            if value.trim().is_empty() {
                continue;
            }
            let escaped = escape_text(&value);
            if expanded || prev == Prev::Block {
                out.push('\n');
                out.push_str(&indent);
                out.push_str(&escaped);
            } else {
                out.push_str(&escaped);
            }
            prev = Prev::Text;
        } else if let Some(elem) = child.as_element() {
            let name = elem.name.local.as_ref().to_string();
            let inline = is_inline(&name);
            let void = is_void(&name);

            if void && inline && prev != Prev::Block {
                out.push_str(&open_tag(elem));
                prev = Prev::Inline;
            } else if void && inline {
                out.push('\n');
                out.push_str(&indent);
                out.push_str(&open_tag(elem));
                prev = Prev::Inline;
            } else if void {
                out.push('\n');
                out.push_str(&indent);
                out.push_str(&open_tag(elem));
                out.push('\n');
                out.push_str(&indent);
                prev = Prev::Block;
            } else if inline && prev != Prev::Block {
                write_inline(out, &child);
                prev = Prev::Inline;
            } else {
                let child_expanded = expanded || prev == Prev::Block;
                out.push('\n');
                out.push_str(&indent);
                out.push_str(&open_tag(elem));
                pretty_children(out, &child, depth + 1, child_expanded);
                if inline {
                    out.push_str("</");
                    out.push_str(&name);
                    out.push('>');
                    prev = Prev::Inline;
                } else {
                    out.push('\n');
                    out.push_str(&indent);
                    out.push_str("</");
                    out.push_str(&name);
                    out.push('>');
                    prev = Prev::Block;
                }
            }
        }
    }
}

fn pretty_print(node: &NodeRef) -> String {
    let mut out = String::new();
    if let Some(elem) = node.as_element() {
        let name = elem.name.local.as_ref().to_string();
        if is_void(&name) {
            out.push_str(&open_tag(elem));
        } else if is_inline(&name) {
            write_inline(&mut out, node);
        } else {
            out.push('\n');
            out.push_str(&open_tag(elem));
            pretty_children(&mut out, node, 1, false);
            out.push('\n');
            out.push_str("</");
            out.push_str(&name);
            out.push('>');
        }
    }
    out.push('\n');
    out
}

fn apply_base(node: &NodeDataRef<ElementData>, base: &Url) {
    if node.name.local.as_ref() != "a" {
        return;
    }
    let mut attrs = node.attributes.borrow_mut();
    let href = match attrs.get("href") {
        Some(h) => h.to_string(),
        None => return,
    };
    if let Ok(joined) = base.join(&href) {
        attrs.insert("href", joined.to_string());
    }
}

use clap::{App, Arg};
use kuchiki::traits::*;
use kuchiki::{ElementData, NodeDataRef, NodeRef};
use std::fs::File;
use std::io::Write;
use url::Url;

fn main() {
    let matches = App::new("htmlq")
        .version("0.4.0")
        .author("Michael Maclean <michael@mgdm.net>")
        .about("Runs CSS selectors on HTML")
        .arg(
            Arg::with_name("detect-base")
                .short("B")
                .long("detect-base")
                .help("Try to detect the base URL from the <base> tag in the document. If not found, default to the value of --base, if supplied"),
        )
        .arg(
            Arg::with_name("ignore-whitespace")
                .short("w")
                .long("ignore-whitespace")
                .help("When printing text nodes, ignore those that consist entirely of whitespace"),
        )
        .arg(
            Arg::with_name("pretty")
                .short("p")
                .long("pretty")
                .help("Pretty-print the serialised output"),
        )
        .arg(
            Arg::with_name("text")
                .short("t")
                .long("text")
                .help("Output only the contents of text nodes inside selected elements"),
        )
        .arg(
            Arg::with_name("attribute")
                .short("a")
                .long("attribute")
                .takes_value(true)
                .value_name("attribute")
                .help("Only return this attribute (if present) from selected elements"),
        )
        .arg(
            Arg::with_name("base")
                .short("b")
                .long("base")
                .takes_value(true)
                .value_name("base")
                .help("Use this URL as the base for links"),
        )
        .arg(
            Arg::with_name("filename")
                .short("f")
                .long("filename")
                .takes_value(true)
                .value_name("FILE")
                .help("The input file. Defaults to stdin"),
        )
        .arg(
            Arg::with_name("output")
                .short("o")
                .long("output")
                .takes_value(true)
                .value_name("FILE")
                .help("The output file. Defaults to stdout"),
        )
        .arg(
            Arg::with_name("remove-nodes")
                .short("r")
                .long("remove-nodes")
                .takes_value(true)
                .value_name("SELECTOR")
                .multiple(true)
                .help("Remove nodes matching this expression before output. May be specified multiple times"),
        )
        .arg(
            Arg::with_name("selector")
                .multiple(true)
                .default_value("html")
                .help("The CSS expression to select"),
        )
        .get_matches();

    // Collect the simple boolean flags up front.
    let use_pretty = matches.is_present("pretty");
    let use_text = matches.is_present("text");
    let ignore_ws = matches.is_present("ignore-whitespace");
    let detect_base = matches.is_present("detect-base");

    // Collect the value-bearing options.
    let attribute = matches.value_of("attribute");
    let cli_base = matches.value_of("base");
    let output_path = matches.value_of("output");
    let input_path = matches.value_of("filename");

    // Positional selectors are joined with a space to form a single CSS query.
    let selector_parts: Vec<&str> = matches.values_of("selector").unwrap().collect();
    let selector = selector_parts.join(" ");

    // The remove-nodes option may be repeated and may take multiple values.
    let remove_nodes: Vec<&str> = matches
        .values_of("remove-nodes")
        .map(|values| values.collect())
        .unwrap_or_default();

    // Read the input document, either from a named file or from stdin. The
    // bytes are fed straight into the html5ever UTF-8 decoder so that invalid
    // sequences become replacement characters rather than hard errors.
    //
    // The parser is configured the same way regardless of the input source;
    // only the reader differs between the file and stdin code paths below.
    //
    // When a filename is supplied but cannot be opened, the failure is fatal
    // and surfaces as a panic carrying the underlying operating-system error.
    let document = match input_path {
        Some(path) => {
            let file = File::open(path).expect("should have opened input file");
            let mut reader = std::io::BufReader::new(file);
            kuchiki::parse_html()
                .from_utf8()
                .read_from(&mut reader)
                .expect("should have read input file")
        }
        None => {
            let stdin = std::io::stdin();
            let mut reader = stdin.lock();
            kuchiki::parse_html()
                .from_utf8()
                .read_from(&mut reader)
                .expect("should have read input from stdin")
        }
    };

    // Work out which base URL, if any, should be applied to anchor hrefs.
    // Detection from the document's <base> tag takes priority; the --base
    // value is only used as a fallback when detection is requested but no
    // usable absolute URL is found in the document.
    let mut base_url: Option<Url> = None;
    if detect_base {
        if let Ok(found) = document.select("base") {
            for base_node in found {
                let attrs = base_node.attributes.borrow();
                if let Some(href) = attrs.get("href") {
                    if let Ok(parsed) = Url::parse(href) {
                        base_url = Some(parsed);
                        break;
                    }
                }
            }
        }
    }
    if base_url.is_none() {
        if let Some(supplied) = cli_base {
            if let Ok(parsed) = Url::parse(supplied) {
                base_url = Some(parsed);
            }
        }
    }

    // Detach every node matching a --remove-nodes selector before selection.
    for remove_selector in &remove_nodes {
        if let Ok(found) = document.select(remove_selector) {
            let doomed: Vec<NodeRef> = found.map(|n| n.as_node().clone()).collect();
            for node in doomed {
                node.detach();
            }
        }
    }

    // Open the output sink: a named file when requested, otherwise stdout.
    let mut out_sink: Box<dyn Write> = match output_path {
        Some(path) => Box::new(File::create(path).expect("should have created output file")),
        None => Box::new(std::io::stdout()),
    };

    // Compile and run the main selector against the parsed document.
    let selected = document
        .select(&selector)
        .expect("Failed to parse CSS selector");

    for node in selected {
        if let Some(ref base) = base_url {
            apply_base(&node, base);
        }

        if let Some(attr) = attribute {
            let attrs = node.attributes.borrow();
            if let Some(value) = attrs.get(attr) {
                writeln!(out_sink, "{}", value).ok();
            }
        } else if use_text {
            if ignore_ws {
                for descendant in node.as_node().inclusive_descendants() {
                    if let Some(text) = descendant.as_text() {
                        let value = text.borrow();
                        if !value.trim().is_empty() {
                            writeln!(out_sink, "{}", value).ok();
                        }
                    }
                }
                writeln!(out_sink).ok();
            } else {
                let mut buffer = String::new();
                for descendant in node.as_node().inclusive_descendants() {
                    if let Some(text) = descendant.as_text() {
                        buffer.push_str(&text.borrow());
                    }
                }
                writeln!(out_sink, "{}", buffer).ok();
            }
        } else if use_pretty {
            out_sink
                .write_all(pretty_print(node.as_node()).as_bytes())
                .ok();
        } else {
            node.as_node().serialize(&mut out_sink).ok();
            writeln!(out_sink).ok();
        }
    }
}

