                .takes_value(true)
                .value_name("FILE")
                .help("The input file. Defaults to stdin"),
        )
        .arg(
            Arg::with_name("output")
                .short("o")
                .long("output")
                .takes_value(true)
                .value_name("FILE")
                .help("The output file. Defaults to stdout"),
        )
        .arg(
            Arg::with_name("remove-nodes")
                .short("r")
                .long("remove-nodes")
                .takes_value(true)
                .value_name("SELECTOR")
                .multiple(true)
                .help("Remove nodes matching this expression before output. May be specified multiple times"),
        )
        .arg(
            Arg::with_name("selector")
                .multiple(true)
                .default_value("html")
                .help("The CSS expression to select"),
        )
        .get_matches();

    // The simple boolean flags.
    let use_pretty = matches.is_present("pretty");
    let use_text = matches.is_present("text");
    let ignore_ws = matches.is_present("ignore-whitespace");
    let detect_base = matches.is_present("detect-base");

    // The value-bearing options.
    let attribute = matches.value_of("attribute");
    let cli_base = matches.value_of("base");
    let output_path = matches.value_of("output");
    let input_path = matches.value_of("filename");

    // Positional selectors are joined with a space to form a single CSS query.
    let selector_parts: Vec<&str> = matches.values_of("selector").unwrap().collect();
    let selector = selector_parts.join(" ");

    // The remove-nodes option may be repeated and may take multiple values.
    let remove_nodes: Vec<&str> = matches
        .values_of("remove-nodes")
        .map(|values| values.collect())
        .unwrap_or_default();

    //
    // ----------------------------------------------------------------------
    // Input handling
    // ----------------------------------------------------------------------
    //
    // The reference accepts its document either from a named file (via the
    // --filename option) or, when no filename is given, from standard input.
    //
    // The bytes of the document are handed straight to the html5ever UTF-8
    // decoder. That decoder is deliberately lenient: byte sequences that are
    // not valid UTF-8 are turned into U+FFFD replacement characters rather
    // than aborting the parse. A leading byte-order mark is also consumed by
    // the decoder. This means that essentially any byte stream is accepted
    // as input and produces some document tree, however damaged the bytes.
    //
    // The parser itself is configured identically on both code paths; only
    // the reader handed to read_from differs between the file and the stdin
    // branches. The file branch wraps the open file in a BufReader, and the
    // stdin branch locks the global standard-input handle for the duration
    // of the read.
    //
    // Failures are treated as fatal. When a filename is supplied but cannot
    // be opened — for instance because the path does not exist or cannot be
    // read — the process panics, and the panic message carries the original
    // operating-system error so the user can see exactly what went wrong.
    // The same is true if the open succeeds but the subsequent read fails.
    //
    // Because a panic during input handling occurs before any output has
    // been produced, a failed run leaves standard output completely empty
    // and exits with the standard Rust panic status rather than a graceful
    // non-zero code. This is intentional: the reference does not attempt to
    // recover from, or prettify, input errors in any way whatsoever here.
    //
    let document = if let Some(path) = input_path {
        let file = File::open(path).expect("should have opened input file");
        let mut reader = std::io::BufReader::new(file);
        kuchiki::parse_html()
            .from_utf8()
            .read_from(&mut reader)
            .expect("should have read the input file")
    } else {
        let stdin = std::io::stdin();
        let mut handle = stdin.lock();
        kuchiki::parse_html()
            .from_utf8()
            .read_from(&mut handle)
            .expect("should have read standard input")
    };

    // Detach every node matching a --remove-nodes selector before selection.
    for remove_selector in &remove_nodes {
        if let Ok(found) = document.select(remove_selector) {
            let doomed: Vec<NodeRef> = found.map(|n| n.as_node().clone()).collect();
            for node in doomed {
                node.detach();
            }
        }
    }

    let selected = document.select(&selector)
        .expect("Failed to parse CSS selector");

    // Work out which base URL, if any, should be applied to anchor hrefs.
    // Detection from the document's <base> tag takes priority; the --base
    // value is only used as a fallback when detection is requested but no
    // usable absolute URL is found in the document.
    let mut base_url: Option<Url> = None;
    if detect_base {
        if let Ok(found) = document.select("base") {
            for base_node in found {
                let attrs = base_node.attributes.borrow();
                if let Some(href) = attrs.get("href") {
                    if let Ok(parsed) = Url::parse(href) {
                        base_url = Some(parsed);
                        break;
                    }
                }
            }
        }
    }
    if base_url.is_none() {
        if let Some(supplied) = cli_base {
            if let Ok(parsed) = Url::parse(supplied) {
                base_url = Some(parsed);
            }
        }
    }

    // Open the output sink: a named file when requested, otherwise stdout.
    let mut out_sink: Box<dyn Write> = match output_path {
        Some(path) => Box::new(File::create(path).expect("should have created output file")),
        None => Box::new(std::io::stdout()),
    };

    for node in selected {
        if let Some(ref base) = base_url {
            apply_base(&node, base);
        }

        if let Some(attr) = attribute {
            let attrs = node.attributes.borrow();
            if let Some(value) = attrs.get(attr) {
                writeln!(out_sink, "{}", value).ok();
            }
        } else if use_text {
            if ignore_ws {
                for descendant in node.as_node().inclusive_descendants() {
                    if let Some(text) = descendant.as_text() {
                        let value = text.borrow();
                        if !value.trim().is_empty() {
                            writeln!(out_sink, "{}", value).ok();
                        }
                    }
                }
                writeln!(out_sink).ok();
            } else {
                let mut buffer = String::new();
                for descendant in node.as_node().inclusive_descendants() {
                    if let Some(text) = descendant.as_text() {
                        buffer.push_str(&text.borrow());
                    }
                }
                writeln!(out_sink, "{}", buffer).ok();
            }
        } else if use_pretty {
            out_sink
                .write_all(pretty_print(node.as_node()).as_bytes())
                .ok();
        } else {
            node.as_node().serialize(&mut out_sink).ok();
            writeln!(out_sink).ok();
        }
    }
}

