// Render the children of `node`. Children sit at indent level `depth`.
// `expanded` is true when the surrounding context requires that the children
// be rendered in "broken" style: text starts on its own line, block elements
// open in expanded mode rather than compact mode, and inline elements whose
// position calls for a break behave likewise.
fn pretty_children(out: &mut String, node: &NodeRef, depth: usize, expanded: bool) {
    let indent = "  ".repeat(depth);
    let mut prev = Prev::None;
    for child in node.children() {
        if let Some(t) = child.as_text() {
            let value = t.borrow();
            if value.trim().is_empty() {
                continue;
            }
            let escaped = escape_text(&value);
            let on_new_line =
                prev == Prev::Block || (prev == Prev::None && expanded);
            if on_new_line {
                out.push('\n');
                out.push_str(&indent);
                out.push_str(&escaped);
            } else {
                out.push_str(&escaped);
            }
            prev = Prev::Text;
        } else if let Some(elem) = child.as_element() {
            prev = render_element(out, &child, &elem, depth, expanded, prev);
        }
    }
    drop(indent);
}

// Render one element at indent level `depth`. `expanded` is the parent's
// expansion mode (for content rules), `prev` is the previous sibling's
// classification. Returns this element's classification for the next sibling.
fn render_element(
    out: &mut String,
    node: &NodeRef,
    elem: &ElementData,
    depth: usize,
    expanded: bool,
    prev: Prev,
) -> Prev {
    let name = elem.name.local.as_ref().to_string();
    let inline = is_inline(&name);
    let void = is_void(&name);
    let indent = "  ".repeat(depth);
    let needs_break = prev == Prev::Block || (prev == Prev::None && expanded);

    if void {
        if inline && !needs_break {
            out.push_str(&open_tag(elem));
            return Prev::Inline;
        }
        if inline {
            out.push('\n');
            out.push_str(&indent);
            out.push_str(&open_tag(elem));
            return Prev::Inline;
        }
        out.push('\n');
        out.push_str(&indent);
        out.push_str(&open_tag(elem));
        out.push('\n');
        out.push_str(&indent);
        return Prev::Block;
    }

    if inline && !needs_break {
        out.push_str(&open_tag(elem));
        pretty_children(out, node, depth + 1, false);
        out.push_str("</");
        out.push_str(&name);
        out.push('>');
        return Prev::Inline;
    }

    if inline {
        out.push('\n');
        out.push_str(&indent);
        out.push_str(&open_tag(elem));
        pretty_children(out, node, depth + 1, true);
        out.push_str("</");
        out.push_str(&name);
        out.push('>');
        return Prev::Inline;
    }

    out.push('\n');
    out.push_str(&indent);
    out.push_str(&open_tag(elem));
    pretty_children(out, node, depth + 1, needs_break);
    out.push('\n');
    out.push_str(&indent);
    out.push_str("</");
    out.push_str(&name);
    out.push('>');
    Prev::Block
}

