            pretty_children(&mut out, node, 1, false);
            out.push_str("</");
            out.push_str(&name);
            out.push('>');
        } else {
            out.push('\n');
            out.push_str(&open_tag(elem));
            pretty_children(&mut out, node, 1, false);
            out.push('\n');
            out.push_str("</");
            out.push_str(&name);
            out.push('>');
        }
    }
