    if let Ok(found) = document.select(remove_selector) {
        let nodes: Vec<NodeRef> = found.map(|n| n.as_node().clone()).collect();
        for n in &nodes {
            tainted.insert(node_key(n));
            for ancestor in n.ancestors() {
                tainted.insert(node_key(&ancestor));
            }
        }
        for n in &nodes {
            n.detach();
        }
    }
}

// Stage 4: work out which base URL, if any, should be applied to anchor
// hrefs. Detection from the document's <base> tag takes priority; the
// --base value is only used as a fallback when detection is requested
// but no usable absolute URL is found in the document.
